ur3e = loadrobot('universalUR3e', DataFormat='column');
Config = [0,-pi/3,pi/7,pi/2,pi/2,0]';

J_toolbox = geometricJacobian(ur3e, Config, 'tool0');

syms q1 q2 q3 q4 q5 q6 real
J_sub = double(subs(J, [q1,q2,q3,q4,q5,q6], ...
     [Config(1)+pi, Config(2:6)']));

J_diff = double(round(J_sub,4) - round(J_toolbox,4));

isCorrect = all(abs(J_diff(:)) < 1e-4);

if isCorrect
    disp('[OK] Symbolic Jacobian matches Toolbox Jacobian');
else
    disp('[FAIL] Symbolic Jacobian does NOT match Toolbox Jacobian');
end
